mapper.select:
/*RskMgmtMapper.selectSaleSttcListExcel*/ SELECT A.CONTRACT_NUM , A.RATE_CD AS ADD_PROD , FN_GET_RATENM(A.RATE_CD) AS ADD_PROD_NM , A.STRT_DT AS STRT_DT , A.END_DT AS END_DT , A.STAT_CD AS STAT_CD , DECODE(A.STAT_CD, 'C', '해지', '사용') AS STAT_NM , B.LST_COM_ACTV_DATE AS OPEN_DT , C.FST_RATE_CD AS FST_RATE_CD , FN_GET_RATENM(C.FST_RATE_CD) AS FST_RATE_NM , C.LST_RATE_CD AS LST_RATE_CD , FN_GET_RATENM(C.LST_RATE_CD) AS LST_RATE_NM , SUBSTR(C.INST_INFO, 1, 2) AS CD_TYPE , FN_GET_CODENM('CMN0058', SUBSTR(C.INST_INFO, 1, 2)) AS DC_TYPE_NM , C.SALE_PLCY_CD AS SALE_PLCY_CD , C.SALE_PLCY_NM AS SALE_PLCY_NM , TRIM(SUBSTR(C.FST_MODEL_INFO, 1, 20)) AS FST_MODEL_ID , TRIM(SUBSTR(C.FST_MODEL_INFO, 21, 30)) AS FST_MODEL_NM , B.OPEN_AGNT_CD AS OPEN_AGNT_CD , FN_GET_ORGNM(B.OPEN_AGNT_CD) AS OPEN_AGNT_NM FROM MSP_ADD_PROD_STTC A , MSP_JUO_SUB_INFO B , MSP_REQUEST_DTL C , MSP_RATE_MST D WHERE A.CONTRACT_NUM = B.CONTRACT_NUM AND B.CONTRACT_NUM = C.CONTRACT_NUM AND A.RATE_CD = D.RATE_CD
AND A.STRT_DT BETWEEN #{strtDt} AND #{endDt}
AND A.RATE_CD = #{searchName}
AND D.RATE_NM LIKE '%' || #{searchName} || '%'
ORDER BY A.CONTRACT_NUM, A.RATE_CD
